CREATE TABLE IF NOT EXISTS income (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), source VARCHAR(100) NOT NULL, amount NUMERIC(10,2) NOT NULL, date DATE NOT NULL, is_recurring BOOLEAN DEFAULT FALSE, notes TEXT);
CREATE TABLE IF NOT EXISTS recurring_expenses (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), title VARCHAR(100) NOT NULL, category VARCHAR(50) NOT NULL, amount NUMERIC(10,2) NOT NULL, frequency VARCHAR(20) DEFAULT 'monthly', next_due DATE NOT NULL, description TEXT, is_active BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS savings_goals (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), name VARCHAR(100) NOT NULL, target_amount NUMERIC(10,2) NOT NULL, saved_amount NUMERIC(10,2) DEFAULT 0, deadline DATE, icon VARCHAR(50) DEFAULT 'fa-bullseye', color VARCHAR(20) DEFAULT '#4f46e5', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS tags (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), name VARCHAR(50) NOT NULL, color VARCHAR(20) DEFAULT '#6366f1', UNIQUE(user_id, name));
CREATE TABLE IF NOT EXISTS expense_tags (expense_id INTEGER REFERENCES expenses(id) ON DELETE CASCADE, tag_id INTEGER REFERENCES tags(id) ON DELETE CASCADE, PRIMARY KEY (expense_id, tag_id));
ALTER TABLE users ADD COLUMN IF NOT EXISTS profile_pic TEXT;
ALTER TABLE users ADD COLUMN IF NOT EXISTS created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP;
ALTER TABLE expenses ADD COLUMN IF NOT EXISTS receipt_path TEXT;
ALTER TABLE expenses ADD COLUMN IF NOT EXISTS tags TEXT;
SELECT 'MIGRATION COMPLETE' AS status;
